invariant wlmdFailureInNextSnapshot implies nextSnapshotModeIsRescue[self];

default init(c : ControlProgram) : Boolean = true;

let nextSnapshotModeIsRescue (cp:ControlProgram) : Boolean = 
   let sn : Snapshot = cp.snapshots->select(s | s.controlProgram == cp and s.position = min{ss.position | ss in cp.snapshots})->asSet()->iterate(b : Boolean, s : Snapshot | b or s.mode = Mode::Rescue);
   sn notEmpty implies sn->last().mode = Mode::Rescue;
endlet;

