	association end Book author; 
	association end Book member; 
	association end Loan copy; 
	association end Loan member; 
	association end Fine loan; 
	enum Genre = {Lyric, Epic, Narrative, Dramatic, Didactic, Horror}; 
	enum State = {Good, Bad}; 
	class Book = {ISBN : EString, title : EString, editorial : EString, year : EInt, genre : Genre, active : EBoolean}; 
