	class Member = {membershipNumber : EInt, name : EString, phone : EString, address : EString, age : EInt, birthDate : EDate}; 
	class Fine = {date : EDate, amount : EInt, exceedingDays : EInt, paymentDate : EDate}; 
	class Copy = {copyNumber : EInt, state : State}; 
	constraint endDate_is_not_null: 
		self.Loan.endDate <> null; 
};

